def detect_smurfing(transactions):
    """Detects smurfing by checking if a user has made 3 or more transactions."""
    user_counts = {}
    for t in transactions:
        user_counts[t['user_id']] = user_counts.get(t['user_id'], 0) + 1
    return any(count >= 3 for count in user_counts.values())
